          </div>
        </div>
        <button onClick={() => handleAddEvent(new Date())} className="flex items-center gap-2 px-4 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold text-sm">
          <Plus className="w-4 h-4" /> 이벤트 추가
        </button>
      </div>
      {/* Grid rendering month view calendar */}
      {/* ... */}
    </div>
  );
};

