// State
let currentDate = new Date(2026, 2, 11); // March 11, 2026
let view = 'month'; // 'month' | 'week' | 'day'
let events = [
  { id: '1', title: '이벤트 컨퍼런스', startDate: new Date(2026, 2, 11), endDate: new Date(2026, 2, 11), type: 'danger' },
  { id: '2', title: '회의', startDate: new Date(2026, 2, 12), endDate: new Date(2026, 2, 12), type: 'success' },
  { id: '3', title: '워크샵', startDate: new Date(2026, 2, 13), endDate: new Date(2026, 2, 13), type: 'primary' }
];
let activeEventId = null;

// DOM Elements
const monthYearTitle = document.getElementById('month-year-title');
const calendarGrid = document.getElementById('calendar-grid');
const addEventBtn = document.getElementById('add-event-btn');
const eventModal = document.getElementById('event-modal');
const modalTitle = document.getElementById('modal-title');
const eventTitleInput = document.getElementById('event-title-input');
const eventTypeInputs = document.getElementsByName('event-type');
const startDateInput = document.getElementById('start-date-input');
const endDateInput = document.getElementById('end-date-input');
const cancelBtn = document.getElementById('cancel-btn');
const saveBtn = document.getElementById('save-btn');
const prevBtn = document.getElementById('prev-btn');
const nextBtn = document.getElementById('next-btn');
const viewButtons = {
  month: document.getElementById('view-month-btn'),
  week: document.getElementById('view-week-btn'),
  day: document.getElementById('view-day-btn')
};

// Colors mapping
const eventStyles = {
  danger: 'bg-red-50 dark:bg-red-500/10 text-red-600 dark:text-red-400 border-l-4 border-red-500',
  success: 'bg-emerald-50 dark:bg-emerald-500/10 text-emerald-600 dark:text-emerald-400 border-l-4 border-emerald-500',
  primary: 'bg-indigo-50 dark:bg-indigo-500/10 text-indigo-600 dark:text-indigo-400 border-l-4 border-[#4B62FA]',
  warning: 'bg-orange-50 dark:bg-orange-500/10 text-orange-600 dark:text-orange-400 border-l-4 border-orange-500'
};

// Format helpers
function formatMonthYear(date) {
  return date.toLocaleDateString('en-US', { month: 'long', year: 'numeric' });
}

function formatDate(date) {
  return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
}

function getWeekRange(date) {
  const start = new Date(date);
  start.setDate(date.getDate() - date.getDay());
  const end = new Date(start);
  end.setDate(start.getDate() + 6);
  return start.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }) + ' – ' + end.toLocaleDateString('en-US', { day: 'numeric', year: 'numeric' });
}

// Render Functions
function render() {
  if (view === 'month') {
    monthYearTitle.textContent = formatMonthYear(currentDate);
  } else if (view === 'week') {
    monthYearTitle.textContent = getWeekRange(currentDate);
  } else {
    monthYearTitle.textContent = formatDate(currentDate);
  }

  Object.keys(viewButtons).forEach(v => {
    if (v === view) {
      viewButtons[v].className = 'px-4 py-1.5 rounded-md text-[13px] font-bold bg-white dark:bg-slate-700 text-slate-900 dark:text-white shadow-sm transition-all cursor-pointer';
    } else {
      viewButtons[v].className = 'px-4 py-1.5 rounded-md text-[13px] font-bold text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200 transition-all cursor-pointer';
    }
  });

  if (view === 'month') {
    renderMonth();
  } else if (view === 'week') {
    renderWeek();
  } else {
    renderDay();
  }

  if (window.lucide) {
    lucide.createIcons();
  }
}

function getDaysInMonth(year, month) {
  return new Date(year, month + 1, 0).getDate();
}

function getFirstDayOfMonth(year, month) {
  return new Date(year, month, 1).getDay();
}

function renderMonth() {
  let html = '<div class="grid grid-cols-7 border-b border-slate-200 dark:border-slate-700 bg-slate-50/50 dark:bg-slate-800/20">';
  const dayNames = ['일', '월', '화', '수', '목', '금', '토'];
  for (let d of dayNames) {
    html += '<div class="py-3 text-center text-[12px] font-bold text-slate-400 dark:text-slate-500">' + d + '</div>';
  }
  html += '</div><div class="grid grid-cols-7">';

  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();
  const daysInMonth = getDaysInMonth(year, month);
  const firstDay = getFirstDayOfMonth(year, month);

  const prevDaysInMonth = getDaysInMonth(year, month - 1);
  for (let i = firstDay - 1; i >= 0; i--) {
    const day = prevDaysInMonth - i;
    html += '<div class="min-h-[100px] p-2 border-r border-b border-slate-100 dark:border-slate-800 bg-slate-50/20 opacity-30 cursor-not-allowed">';
    html += '<div class="flex justify-start mb-1"><span class="text-[13px] font-bold text-slate-400">' + day + '</span></div>';
    html += '</div>';
  }

  for (let day = 1; day <= daysInMonth; day++) {
    const isToday = day === 11 && month === 2 && year === 2026;
    const thisDate = new Date(year, month, day);
    const dayEvents = events.filter(e => {
      const s = new Date(e.startDate);
      const ed = new Date(e.endDate);
      const d = new Date(year, month, day);
      s.setHours(0,0,0,0);
      ed.setHours(0,0,0,0);
      d.setHours(0,0,0,0);
      return d >= s && d <= ed;
    });

    const isLastCol = (firstDay + day - 1) % 7 === 6;

    html += '<div onclick="handleAddEventAt(\'' + thisDate.toISOString() + '\')" class="min-h-[100px] p-2 border-r ' + (isLastCol ? '' : 'border-r') + ' border-b border-slate-200 dark:border-slate-800 cursor-pointer hover:bg-slate-50/50 dark:hover:bg-slate-800/30 transition-all ' + (isToday ? 'bg-indigo-50/30 dark:bg-indigo-500/5' : '') + '">';
    html += '<div class="flex justify-between items-center mb-1">';
    html += '<span class="text-[13px] font-black ' + (isToday ? 'bg-[#4B62FA] text-white w-6 h-6 flex items-center justify-center rounded-full' : 'text-slate-800 dark:text-slate-200') + '">' + day + '</span>';
    html += '</div>';
    html += '<div class="space-y-1">';
    for (let e of dayEvents) {
      const style = eventStyles[e.type] || eventStyles.primary;
      html += '<div onclick="event.stopPropagation(); handleEditEvent(\'' + e.id + '\')" class="px-2 py-0.5 rounded text-[10px] font-bold truncate ' + style + ' cursor-pointer hover:brightness-95 transition-all">' + e.title + '</div>';
    }
    html += '</div></div>';
  }

  const totalCells = Math.ceil((firstDay + daysInMonth) / 7) * 7;
  const nextMonthCells = totalCells - (firstDay + daysInMonth);
  for (let day = 1; day <= nextMonthCells; day++) {
    html += '<div class="min-h-[100px] p-2 border-b border-slate-100 dark:border-slate-800 bg-slate-50/20 opacity-30 cursor-not-allowed">';
    html += '<div class="flex justify-start mb-1"><span class="text-[13px] font-bold text-slate-400">' + day + '</span></div>';
    html += '</div>';
  }

  html += '</div>';
  calendarGrid.innerHTML = html;
}

function renderWeek() {
  const daysOfWeek = ['일', '월', '화', '수', '목', '금', '토'];
  const startOfWeek = new Date(currentDate);
  startOfWeek.setDate(currentDate.getDate() - currentDate.getDay());

  const weekDays = [];
  for (let i = 0; i < 7; i++) {
    const d = new Date(startOfWeek);
    d.setDate(startOfWeek.getDate() + i);
    weekDays.push(d);
  }

  const timeSlots = ['하루 종일', '오전 7시', '오전 8시', '오전 9시', '오전 10시', '오전 11시', '오후 12시', '오후 1시', '오후 2시', '오후 3시', '오후 4시', '오후 5시', '오후 6시'];

  let html = '<div class="flex flex-col border-t border-slate-200 dark:border-slate-800">';
  html += '<div class="grid grid-cols-8 border-b border-slate-200 dark:border-slate-800 bg-slate-50/30 dark:bg-slate-800/30">';
  html += '<div class="border-r border-slate-200 dark:border-slate-800"></div>';
  weekDays.forEach((d, i) => {
    html += '<div class="py-4 text-center border-r border-slate-200 dark:border-slate-800 last:border-r-0">';
    html += '<span class="text-[12px] font-bold text-slate-500 dark:text-slate-400">' + daysOfWeek[i] + ' ' + (d.getMonth() + 1) + '/' + d.getDate() + '</span>';
    html += '</div>';
  });
  html += '</div><div class="overflow-y-auto max-h-[600px] custom-scrollbar">';

  timeSlots.forEach(time => {
    html += '<div class="grid grid-cols-8 border-b border-slate-100 dark:border-slate-800/50">';
    html += '<div class="p-3 text-[11px] font-bold text-slate-400 dark:text-slate-500 border-r border-slate-200 dark:border-slate-800 text-right pr-4 uppercase">' + time + '</div>';
    weekDays.forEach((d, i) => {
      let eventHtml = '';
      if (time === '하루 종일' && i === 3) {
        eventHtml = '<div class="absolute inset-x-1 top-1 bottom-1 px-2 py-1 rounded text-[10px] font-bold ' + eventStyles.danger + '">이벤트 컨퍼런스</div>';
      } else if (time === '오전 7시' && i === 4) {
        eventHtml = '<div class="absolute inset-x-1 top-1 bottom-1 px-2 py-1 rounded text-[10px] font-bold ' + eventStyles.success + '">회의</div>';
      } else if (time === '오전 7시' && i === 5) {
        eventHtml = '<div class="absolute inset-x-1 top-1 bottom-1 px-2 py-1 rounded text-[10px] font-bold ' + eventStyles.primary + '">워크샵</div>';
      }
      html += '<div onclick="handleAddEventAt(\'' + d.toISOString() + '\')" class="border-r border-slate-100 dark:border-slate-800/50 last:border-r-0 relative min-h-[50px] group transition-colors cursor-pointer hover:bg-slate-50/50 dark:hover:bg-slate-800/20 active:bg-slate-100 dark:active:bg-slate-800/40">' + eventHtml + '</div>';
    });
    html += '</div>';
  });
  html += '</div></div>';

  calendarGrid.innerHTML = html;
}

function renderDay() {
  const timeSlots = ['하루 종일', '오전 7시', '오전 8시', '오전 9시', '오전 10시', '오전 11시', '오후 12시', '오후 1시', '오후 2시', '오후 3시', '오후 4시', '오후 5시', '오후 6시'];

  let html = '<div class="flex flex-col border-t border-slate-200 dark:border-slate-800">';
  html += '<div class="grid grid-cols-[100px_1fr] border-b border-slate-200 dark:border-slate-800 bg-slate-50/30 dark:bg-slate-800/30">';
  html += '<div class="border-r border-slate-200 dark:border-slate-800"></div>';
  html += '<div class="py-4 text-center uppercase tracking-widest text-[12px] font-bold text-slate-500 dark:text-slate-400">' + currentDate.toLocaleDateString('en-US', { weekday: 'long' }) + '</div>';
  html += '</div><div class="overflow-y-auto max-h-[600px] custom-scrollbar">';

  timeSlots.forEach(time => {
    html += '<div class="grid grid-cols-[100px_1fr] border-b border-slate-100 dark:border-slate-800/50">';
    html += '<div class="p-4 text-[12px] font-bold text-slate-400 dark:text-slate-500 border-r border-slate-200 dark:border-slate-800 text-right pr-6 uppercase leading-none">' + time + '</div>';
    html += '<div onclick="handleAddEventAt(\'' + currentDate.toISOString() + '\')" class="relative min-h-[60px] group transition-colors cursor-pointer hover:bg-slate-50/50 dark:hover:bg-slate-800/20 active:bg-slate-100 dark:active:bg-slate-800/40"></div>';
    html += '</div>';
  });
  html += '</div></div>';

  calendarGrid.innerHTML = html;
}

function handlePrev() {
  if (view === 'month') currentDate.setMonth(currentDate.getMonth() - 1);
  else if (view === 'week') currentDate.setDate(currentDate.getDate() - 7);
  else currentDate.setDate(currentDate.getDate() - 1);
  render();
}

function handleNext() {
  if (view === 'month') currentDate.setMonth(currentDate.getMonth() + 1);
  else if (view === 'week') currentDate.setDate(currentDate.getDate() + 7);
  else currentDate.setDate(currentDate.getDate() + 1);
  render();
}

function handleAddEvent() {
  activeEventId = null;
  modalTitle.textContent = '이벤트 추가';
  eventTitleInput.value = '';
  startDateInput.value = formatDateString(currentDate);
  endDateInput.value = formatDateString(currentDate);
  eventTypeInputs[0].checked = true;
  eventModal.classList.remove('hidden');
}

function handleAddEventAt(dateStr) {
  activeEventId = null;
  modalTitle.textContent = '이벤트 추가';
  eventTitleInput.value = '';
  const date = new Date(dateStr);
  startDateInput.value = formatDateString(date);
  endDateInput.value = formatDateString(date);
  eventTypeInputs[0].checked = true;
  eventModal.classList.remove('hidden');
}

function handleEditEvent(id) {
  const ev = events.find(e => e.id === id);
  if (!ev) return;
  activeEventId = id;
  modalTitle.textContent = '이벤트 수정';
  eventTitleInput.value = ev.title;
  startDateInput.value = formatDateString(new Date(ev.startDate));
  endDateInput.value = formatDateString(new Date(ev.endDate));
  for (let radio of eventTypeInputs) {
    if (radio.value === ev.type) radio.checked = true;
  }
  eventModal.classList.remove('hidden');
}

function closeModal() {
  eventModal.classList.add('hidden');
}

function formatDateString(date) {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, '0');
  const d = String(date.getDate()).padStart(2, '0');
  return y + '-' + m + '-' + d;
}

prevBtn.addEventListener('click', handlePrev);
nextBtn.addEventListener('click', handleNext);
viewButtons.month.addEventListener('click', () => { view = 'month'; render(); });
viewButtons.week.addEventListener('click', () => { view = 'week'; render(); });
viewButtons.day.addEventListener('click', () => { view = 'day'; render(); });
addEventBtn.addEventListener('click', handleAddEvent);
cancelBtn.addEventListener('click', closeModal);

saveBtn.addEventListener('click', (e) => {
  e.preventDefault();
  const title = eventTitleInput.value.trim();
  if (!title) return;

  let selectedType = 'primary';
  for (let radio of eventTypeInputs) {
    if (radio.checked) selectedType = radio.value;
  }

  const sDate = new Date(startDateInput.value);
  const eDate = new Date(endDateInput.value);

  if (activeEventId) {
    events = events.map(ev => ev.id === activeEventId ? { ...ev, title, type: selectedType, startDate: sDate, endDate: eDate } : ev);
  } else {
    events.push({
      id: Math.random().toString(36).substr(2, 9),
      title,
      type: selectedType,
      startDate: sDate,
      endDate: eDate
    });
  }
  closeModal();
  render();
});

render();
